import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"基金常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/fund-faq.md","filePath":"zh-CN/funds-and-wealth/funds/fund-faq.md"}'),h={name:"funds-and-wealth/funds/fund-faq.md"};function n(l,a,i,d,s,u){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="基金常见问题" tabindex="-1">基金常见问题 <a class="header-anchor" href="#基金常见问题" aria-label="Permalink to &quot;基金常见问题&quot;">​</a></h1><p>基金分红、交易截止时间、融资购买限制及基金持仓相关常见问题。</p><h2 id="常见问题解答" tabindex="-1">常见问题解答 <a class="header-anchor" href="#常见问题解答" aria-label="Permalink to &quot;常见问题解答&quot;">​</a></h2><h3 id="分红是现金还是份额" tabindex="-1">分红是现金还是份额？ <a class="header-anchor" href="#分红是现金还是份额" aria-label="Permalink to &quot;分红是现金还是份额？&quot;">​</a></h3><p>基金分红统一以<strong>份额</strong>形式发放。无论账户设置的是现金分红还是再投资，实际均以基金份额的方式分配。</p><h3 id="基金交易的截止时间是几点" tabindex="-1">基金交易的截止时间是几点？ <a class="header-anchor" href="#基金交易的截止时间是几点" aria-label="Permalink to &quot;基金交易的截止时间是几点？&quot;">​</a></h3><ul><li>普通基金（股票型、债券型、商品型、平衡型）：每日 <strong>12:00（北京时间）</strong></li><li>货币基金：每日 <strong>09:05（北京时间）</strong></li></ul><p>截止时间前提交按当日净值处理，截止时间后提交顺延至下一交易日。</p><h3 id="可以用融资资金买基金吗" tabindex="-1">可以用融资资金买基金吗？ <a class="header-anchor" href="#可以用融资资金买基金吗" aria-label="Permalink to &quot;可以用融资资金买基金吗？&quot;">​</a></h3><p>不支持。融资账户资金不可用于购买基金，只能使用账户中的自有资金。</p><h3 id="卖出多只基金时-赎回顺序是什么" tabindex="-1">卖出多只基金时，赎回顺序是什么？ <a class="header-anchor" href="#卖出多只基金时-赎回顺序是什么" aria-label="Permalink to &quot;卖出多只基金时，赎回顺序是什么？&quot;">​</a></h3><p>系统按照<strong>先买入先赎回</strong>的原则处理，即先买入的份额优先被赎回。</p><h3 id="卖出后资金什么时候到账" tabindex="-1">卖出后资金什么时候到账？ <a class="header-anchor" href="#卖出后资金什么时候到账" aria-label="Permalink to &quot;卖出后资金什么时候到账？&quot;">​</a></h3><p>普通基金卖出后，资金通常在 T+3 日确认净值后的 <strong>7 个交易日内</strong>到账。具体到账时间以实际为准。</p><hr><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><h3 id="日涨跌幅" tabindex="-1">日涨跌幅 <a class="header-anchor" href="#日涨跌幅" aria-label="Permalink to &quot;日涨跌幅&quot;">​</a></h3><p>当日基金净值相对于上一交易日净值的变动百分比。</p><p>公式：日涨跌幅 = (今日单位净值 - 昨日单位净值) ÷ 昨日单位净值 × 100%</p><h3 id="待确认资金" tabindex="-1">待确认资金 <a class="header-anchor" href="#待确认资金" aria-label="Permalink to &quot;待确认资金&quot;">​</a></h3><p>已提交申请但尚未被基金公司确认的资金。买入申请在确认前，对应金额显示为待确认资金；确认后转换为持有份额。</p><h3 id="持有份额" tabindex="-1">持有份额 <a class="header-anchor" href="#持有份额" aria-label="Permalink to &quot;持有份额&quot;">​</a></h3><p>当前账户中已确认持有的基金份额数量。</p><h3 id="单位净值" tabindex="-1">单位净值 <a class="header-anchor" href="#单位净值" aria-label="Permalink to &quot;单位净值&quot;">​</a></h3><p>基金每份的当前价格，由基金公司每个交易日收盘后公布。已扣除管理费、托管费等费用。</p><h3 id="基金总额" tabindex="-1">基金总额 <a class="header-anchor" href="#基金总额" aria-label="Permalink to &quot;基金总额&quot;">​</a></h3><p>持有份额按当前单位净值折算的总市值。</p><p>公式：基金总额 = 持有份额 × 单位净值</p><h3 id="最新收益" tabindex="-1">最新收益 <a class="header-anchor" href="#最新收益" aria-label="Permalink to &quot;最新收益&quot;">​</a></h3><p>当日基金净值变动带来的收益（或亏损）金额。</p><p>公式：最新收益 = 持有份额 × (今日单位净值 - 昨日单位净值)</p><h3 id="持有收益" tabindex="-1">持有收益 <a class="header-anchor" href="#持有收益" aria-label="Permalink to &quot;持有收益&quot;">​</a></h3><p>从买入至今的累计盈亏金额，反映当前持仓的浮动盈亏。</p><p>公式：持有收益 = 基金总额 - 买入总成本</p><h3 id="累计收益" tabindex="-1">累计收益 <a class="header-anchor" href="#累计收益" aria-label="Permalink to &quot;累计收益&quot;">​</a></h3><p>历史上所有已完成交易（已赎回部分）的实际盈亏，加上当前持仓的浮动盈亏之和。</p><p>公式：累计收益 = 历史已实现盈亏 + 当前持有收益</p>',37)])])}const f=e(h,[["render",n]]);export{c as __pageData,f as default};
